  "lb23il": [
    {id:0,x:882.0,y:405.0,type:"mastery-gate",name:"Lightning Blast",maxPoints:0,parentId:undefined,iconId:"a-r-153"},
    {id:2,x:622.8,y:333.0,type:"notable",name:"Arcing Power",maxPoints:4,parentId:0,iconId:"a-r-314",description:"Lightning Blast chains an additional time for each Lightning Blast you have directly cast recently up to a maximum. | Maximum Additional Chains 1; Additional Chains Per Recent Direct Cast 1"},
    {id:3,x:660.0,y:165.0,type:"core",name:"Surging Influence",maxPoints:1,parentId:2,iconId:"a-r-57",description:"Lightning Blast chains have increased range. | Chain Range +50%"},
    {id:4,x:397.2,y:417.0,type:"core",name:"Crackling Speed",maxPoints:4,parentId:2,iconId:"a-r-729",description:"Lightning Blast has increased cast speed. | Cast Speed +5%"},
    {id:5,x:187.2,y:468.6,type:"core",name:"Shattershock",maxPoints:3,parentId:4,iconId:"a-r-844",description:"Lightning Blast hits deal more damage to chilled or shocked enemies (multiplicative with other modifiers). | Hit Damage Against Shocked Enemies +12%; Hit Damage Against Chilled Enemies +12%"},
    {id:6,x:433.0,y:232.6,type:"notable",name:"Closed Circuit",maxPoints:1,parentId:2,iconId:"a-r-41",description:"Lightning Blast can now chain to you or your allies, granting increased damage and critical strike chance for 4 seconds. This buff cannot stack. | Increased Damage Granted 20%; Increased Crit Chance Granted 50%"},
    {id:7,x:247.2,y:292.6,type:"core",name:"Blinding Light",maxPoints:3,parentId:4,iconId:"a-r-71",description:"Lightning Blast hits have a chance to blind enemies. | Blind Chance +15%"},
    {id:8,x:104.8,y:207.0,type:"core",name:"Halo Effect",maxPoints:4,parentId:7,iconId:"a-r-248",description:"Lightning Blast has a chance to create a {Spark Nova} around the first enemy hit. Spark Nova deals spell lightning damage to all enemies in a small area. | Spark Nova Chance 25%"},
    {id:9,x:671.4,y:537.0,type:"core",name:"Volatile Lightning",maxPoints:4,parentId:0,iconId:"a-r-960",description:"Lightning Blast hits have a chance to shock enemies. | Shock Chance +15%"},
    {id:10,x:350.9,y:602.6,type:"notable",name:"Supercharged Floes",maxPoints:1,parentId:9,iconId:"a-r-721",description:"Lightning Blast now has a chance to freeze and its base lightning damage is converted to cold damage. Consequently this damage scales with increases to cold damage, but not increases to lightning damage.  Shock chance from this tree is converted to chill chance. | Freeze Rate 46"},
    {id:11,x:214.8,y:723.0,type:"core",name:"Bitter Burst",maxPoints:5,parentId:10,iconId:"a-r-115",description:"Lightning Blast has a higher chance to freeze enemies. | Freeze Rate Multiplier +40%"},
    {id:12,x:682.8,y:690.6,type:"core",name:"Positive Protection",maxPoints:3,parentId:9,iconId:"a-r-349",description:"Lightning Blast hits grant you ward. | Ward On Hit +2"},
    {id:13,x:528.0,y:761.4,type:"notable",name:"Insidious Conduction",maxPoints:1,parentId:12,iconId:"a-r-838",description:"Lightning Blast is now a powerful channelled attack, hitting enemies caught within it but costs mana per second to channel and provides less ward when you hit enemies. You do not regenerate mana while channelling.  This is incompatible with the {Focal Blast} node. If you have taken both, this will not work.  Lightning Blast cannot double cast and only chains every 5th cast if it is channelled.  Lightning blast hits grant half as much ward from the {Positive Protection} node and have 50% reduced chance to apply ailments. | Mana Cost Per Second 40 (downside); Casts Between Chaining 4 (downside); Ward On Hit -50% (downside)"},
    {id:14,x:831.6,y:769.8,type:"core",name:"Effluent Defense",maxPoints:2,parentId:12,iconId:"a-r-500",description:"Casting Lightning Blast grants you ward per mana spent. This only counts the upfront mana cost, not the channelling cost if Lightning Blast is channelled. | Ward Gained Per Mana Spent 1"},
    {id:15,x:1107.4,y:574.2,type:"core",name:"Storm Razor",maxPoints:3,parentId:0,iconId:"a-r-966",description:"Improves Lightning Blast's base critical strike chance, and Lightning Blast deals more damage (multiplicative with other modifiers). | Base Critical Strike Chance +2%; Damage +5%"},
    {id:16,x:1418.4,y:691.8,type:"notable",name:"Chain Lightning",maxPoints:4,parentId:15,iconId:"a-r-258",description:"Lightning blast can chain additional times, but costs more mana. | Maximum Additional Chains +1; Mana Cost +3 (downside)"},
    {id:17,x:50.4,y:667.8,type:"notable",name:"Focal Blast",maxPoints:1,parentId:11,iconId:"a-r-429",description:"Lightning Blast now deals damage to all enemies in a line, but no longer chains or forks. Lightning Blast hits deal more damage (multiplicative with other modifiers) for each time it would have chained (up to your maximum).  This node is incompatible with the {Insidious Conduction} node. If you have taken both, {Insidious Conduction} will not work. | Damage Per Maximum Additional Chains +30%"},
    {id:18,x:1222.8,y:785.4,type:"notable",name:"Convergence",maxPoints:1,parentId:16,iconId:"a-r-858",description:"Lightning Blast chains now hit the same target after a delay, but no longer chains to additional enemies. Lightning Blast chains half as many times rounded up."},
    {id:19,x:1606.8,y:780.6,type:"core",name:"Divergence",maxPoints:1,parentId:16,iconId:"a-r-364",description:"Lightning Blast hits have added lightning damage, and Lightning Blast chains can fork in addition to chain. | Added Lightning Damage +2"},
    {id:21,x:870.0,y:634.2,type:"core",name:"Lightning Attunement",maxPoints:2,parentId:15,iconId:"a-r-1107",description:"When you cast Lightning Blast you have a chance to be granted {Lightning Aegis,} which grants 50% increased lightning damage and 25% less damage taken. Lightning Aegis causes an explosion of lightning damage when you lose 25% of your health or after 10 seconds. | Lightning Aegis Chance On Cast 5%"},
    {id:22,x:1273.3,y:417.0,type:"core",name:"Overcharge",maxPoints:4,parentId:15,iconId:"a-r-251",description:"Lightning Blast has a chance to double cast, and Lightning Blast critical strikes deal more damage.  Lightning Blast cannot double cast if it is channelled or cast by another skill. | Doublecast Chance 8%; Critical Multiplier +10%"},
    {id:24,x:1107.4,y:259.8,type:"core",name:"Frontloaded",maxPoints:5,parentId:0,iconId:"a-r-1110",description:"Lightning Blast deals more damage (multiplicative with other modifiers), but this damage bonus is lessened each time Lightning Blast chains. | Damage +20%; Less Bonus Damage Per Chain 25% (downside)"},
    {id:25,x:1386.0,y:280.2,type:"core",name:"Cloud Answer",maxPoints:3,parentId:24,iconId:"a-r-141",description:"Lightning Blast hits have a chance to apply a {Spark Charge}. | Spark Charge Chance On Hit 10%"},
    {id:26,x:1587.6,y:369.0,type:"core",name:"Mortal Capacitor",maxPoints:5,parentId:25,iconId:"a-r-203",description:"{Spark Charges} applied by Lightning Blast deal more damage (multiplicative with other modifiers). | Spark Charge Damage +40%"},
    {id:27,x:1587.6,y:177.0,type:"core",name:"Final Spark",maxPoints:1,parentId:25,iconId:"a-r-42",description:"If Lightning Blast hits an enemy already affected by {Spark Charge} the Spark Charge explodes, dealing lightning damage to all nearby enemies."},
    {id:28,x:962.4,y:183.0,type:"core",name:"Innate Conduit",maxPoints:1,parentId:24,iconId:"a-r-845",description:"While out of mana, Lightning Blast has no cost, but cannot chain. | Out-Of-Mana Cost 0"},
    {id:30,x:1107.4,y:417.0,type:"core",name:"Hypercharge",maxPoints:1,parentId:22,iconId:"a-r-313",description:"When double casting, Lightning Blast instead has a chance to quadruple cast.  Lightning Blast cannot quadruple cast if it is channelled. | Quadruple Cast Chance 30%"},
    {id:32,x:348.0,y:783.0,type:"core",name:"Countenance of Mana",maxPoints:2,parentId:13,iconId:"a-r-44",description:"Reduces Lightning Blast's channel cost if Lightning Blast cannot chain. | Mana Cost Per Second if Lightning Blast Cannot Chain -10"},
  ],
