  "srtor": [
    {id:0,x:882.0,y:405.0,type:"mastery-gate",name:"Summon Raptor",maxPoints:0,parentId:undefined,iconId:"a-r-322"},
    {id:2,x:690.0,y:291.0,type:"core",name:"Iridescent Plumage",maxPoints:4,parentId:0,iconId:"a-r-422",description:"Your raptor has additional elemental resistance and have additional dodge chance. | Elemental Resistance +12%; Dodge Rating +100"},
    {id:3,x:416.4,y:281.4,type:"notable",name:"Screech",maxPoints:1,parentId:2,iconId:"a-r-1176",description:"Your raptor gains the ability to {Screech} at enemies, dealing damage and shredding their physical resistance. Screech has an 8 second cooldown. | Physical Resistance Shred Stacks 2"},
    {id:4,x:161.8,y:283.8,type:"core",name:"Earsplitting Roar",maxPoints:4,parentId:3,iconId:"a-r-324",description:"{Screech}'s cooldown is reduced, and it causes enemies it hits to {Bleed}. | Bleed Stacks from Screech 2; Screech Cooldown Reduction (seconds) -0.5"},
    {id:6,x:348.0,y:415.8,type:"core",name:"Clever Girl",maxPoints:4,parentId:3,iconId:"a-r-521",description:"Your raptor has increased cooldown recovery speed for its abilities. | Increased Cooldown Recovery Speed +15%"},
    {id:7,x:528.0,y:173.4,type:"core",name:"Brilliant Display",maxPoints:1,parentId:2,iconId:"a-r-679",description:"Your raptor automatically reduces the cooldown of your other companions' activatable abilities by 3 seconds. This effect has an 8 second cooldown."},
    {id:8,x:690.0,y:543.0,type:"core",name:"Razor Wings",maxPoints:4,parentId:0,iconId:"a-r-720",description:"Your raptor deals more damage (multiplicative with other modifiers) and has increased area of effect for its abilities. | Damage +8%; Area +10%"},
    {id:9,x:391.9,y:567.0,type:"notable",name:"Thrill of the Hunt",maxPoints:1,parentId:8,iconId:"a-r-1194",description:"Your raptor becomes a {Dragon Raptor}. The base physical damage of your raptor's melee attacks are converted to fire. Consequently this damage scales with increases to fire damage, but not with increases to physical damage.  Your raptor gains the {Fire Breath} ability, dealing spell fire damage over time with an 8 second cooldown.  Bleed chance from all sources is converted to ignite chance for your raptor, and all effects in the tree related to bleed now depend on ignite. | Base Melee Damage -> Fire 100%"},
    {id:10,x:197.5,y:687.0,type:"core",name:"Adaptation",maxPoints:4,parentId:9,iconId:"a-r-428",description:"{Fire Breath}'s cooldown is reduced, and it deals more damage (multiplicative with other modifiers). | Cooldown Reduction (seconds) -0.5; Damage +10%"},
    {id:11,x:424.0,y:726.1,type:"notable",name:"Taste for Flesh",maxPoints:3,parentId:8,iconId:"a-r-130",description:"Your raptor has increased attack and cast speed. This effect is doubled if it has killed an enemy in the past 4 seconds. | Attack And Cast Speed +6%"},
    {id:12,x:870.0,y:627.0,type:"core",name:"Scent of Blood",maxPoints:4,parentId:8,iconId:"a-r-225",description:"Your raptor deals more melee damage (multiplicative with other modifiers). | Melee Damage +10%"},
    {id:13,x:1050.0,y:768.6,type:"core",name:"In for the Kill",maxPoints:1,parentId:12,iconId:"a-r-294",description:"When a bleeding enemy dies within 12 meters, your raptor has a chance per stack of bleed on that enemy to gain Haste for 3 seconds. | Chance per Bleed for Haste on Enemy Death 1%"},
    {id:14,x:690.0,y:768.6,type:"core",name:"Ravage",maxPoints:3,parentId:12,iconId:"a-r-78",description:"Your raptor deals more melee damage per bleed on the enemy (multiplicative with other modifiers), up to a maximum. | Max More Melee Damage from Bleed +25%; Melee Damage per Bleed 1%"},
    {id:15,x:1050.0,y:543.0,type:"core",name:"Tear Flesh",maxPoints:5,parentId:0,iconId:"a-r-2",description:"Your raptor's melee attacks have a chance to cause enemies to bleed. | Melee Bleed Chance +40%"},
    {id:16,x:1252.8,y:629.4,type:"core",name:"Sharp Claws",maxPoints:5,parentId:15,iconId:"a-r-1195",description:"Your raptor deals more damage over time (multiplicative with other modifiers). | Damage Over Time +20%"},
    {id:17,x:1412.4,y:739.8,type:"core",name:"Acidic Bile",maxPoints:4,parentId:16,iconId:"a-r-492",description:"Your raptor's attacks have a chance to inflict blind, poison, and slow on hit. | Blind Chance +25%; Poison Chance +25%; Slow Chance +25%"},
    {id:19,x:1534.8,y:567.0,type:"notable",name:"Dripping Blood",maxPoints:1,parentId:16,iconId:"a-r-716",description:"When your raptor hits an enemy, bleeds on that enemy have a 25% chance to double in speed. | Chance On Hit To Double Bleed Speed 25%"},
    {id:20,x:1252.8,y:483.0,type:"core",name:"Cornered",maxPoints:3,parentId:15,iconId:"a-r-31",description:"Your raptor deals more damage for each percent of its missing health (multiplicative with other modifiers), up to 50% missing health. | Damage per 1% Missing Health +1%"},
    {id:21,x:1449.6,y:426.6,type:"notable",name:"Broken Tooth",maxPoints:1,parentId:20,iconId:"a-r-292",description:"Your raptor has increased melee attack speed, but loses 5% of its current health with each attack while above 50% of maximum health. | Melee Attack Speed +10%; Percent Of Current Health Lost On Melee Attack Above 50% 5%"},
    {id:22,x:1050.0,y:291.0,type:"core",name:"Vicious Rampage",maxPoints:4,parentId:0,iconId:"a-r-718",description:"Your raptor gains increased effect from {Rampage}. | Increased Rampage Effect 20%"},
    {id:23,x:1252.8,y:283.8,type:"core",name:"Predator",maxPoints:4,parentId:22,iconId:"a-r-740",description:"Your raptor has additional critical strike chance. | Critical Strike Chance +3%"},
    {id:24,x:1449.6,y:274.2,type:"core",name:"Vexation",maxPoints:4,parentId:23,iconId:"a-r-855",description:"{Rampage}'s duration is increased. | Rampage Duration +25%"},
    {id:25,x:1617.6,y:366.6,type:"core",name:"Eager",maxPoints:3,parentId:24,iconId:"a-r-724",description:"{Rampage} costs less mana. | Rampage Mana Efficiency +40%"},
    {id:26,x:1612.8,y:199.8,type:"notable",name:"Challenger",maxPoints:1,parentId:24,iconId:"a-r-383",description:"Your raptor uses {Rampage} if it encounters a boss or rare enemy, if it is able to. This sets Rampage to 50% of its normal cooldown. | Percent of Normal Cooldown 50%"},
    {id:27,x:1252.8,y:147.0,type:"notable",name:"Primal Rage",maxPoints:1,parentId:22,iconId:"a-r-1196",description:"{Rampage} also grants your raptor less damage taken for the duration. | Rampage Less Damage Taken 20%"},
    {id:28,x:870.0,y:188.0,type:"core",name:"Menacing Aura",maxPoints:2,parentId:22,iconId:"a-r-396",description:"While your raptor is {Rampaging}, its hits instantly kill enemies below a health threshold (a percentage of their maximum health). | Kill Threshold While Rampaging +6%"},
    {id:29,x:146.4,y:551.4,type:"core",name:"Hot Streak",maxPoints:1,parentId:10,iconId:"a-r-24",description:"{Rampage} also resets the cooldown of {Fire Breath}."},
    {id:30,x:1395.6,y:138.6,type:"core",name:"Brutal Shredding",maxPoints:4,parentId:23,iconId:"a-r-131",description:"Your raptor has additional critical strike multiplier, and its attacks have a chance to shred armor on hit. | Critical Multiplier +15%; Armor Shred Chance +25%"},
  ],
